hydrate.query:
query FulfillmentOrderMoveValidationHydrate($first: Int!) {
    locationsAvailableForDeliveryProfilesConnection(first: $first) {
      nodes {
        id
        name
        localPickupSettingsV2 {
          pickupTime
          instructions
        }
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
      }
    }
  }

serviceCreate.query:
mutation FulfillmentOrderMoveValidationServiceCreate($name: String!) {
    fulfillmentServiceCreate(
      name: $name
      trackingSupport: true
      inventoryManagement: true
      requiresShippingMethod: true
    ) {
      fulfillmentService {
        id
        handle
        serviceName
        location {
          id
          name
          isFulfillmentService
          fulfillsOnlineOrders
          shipsInventory
        }
      }
      userErrors {
        field
        message
      }
    }
  }

moveRequestOrderToService.query:
#graphql
  fragment FulfillmentOrderMoveValidationFields on FulfillmentOrder {
    id
    status
    requestStatus
    updatedAt
    assignedLocation {
      name
      location {
        id
        name
      }
    }
    lineItems(first: 5) {
      nodes {
        id
        totalQuantity
        remainingQuantity
        lineItem {
          id
          title
          quantity
          fulfillableQuantity
        }
      }
    }
  }

  mutation FulfillmentOrderMoveValidationMove(
    $id: ID!
    $newLocationId: ID!
    $fulfillmentOrderLineItems: [FulfillmentOrderLineItemInput!]
  ) {
    fulfillmentOrderMove(
      id: $id
      newLocationId: $newLocationId
      fulfillmentOrderLineItems: $fulfillmentOrderLineItems
    ) {
      movedFulfillmentOrder {
        ...FulfillmentOrderMoveValidationFields
      }
      originalFulfillmentOrder {
        ...FulfillmentOrderMoveValidationFields
      }
      remainingFulfillmentOrder {
        ...FulfillmentOrderMoveValidationFields
      }
      userErrors {
        field
        message
        code
      }
    }
  }

